<template><div class="app"><p v-if="!authReady" class="empty">正在验证登录状态...</p><template v-else><component :is="page"/><BottomNav v-if="showBottomNav"/></template></div></template><script setup lang="ts">import{computed,h}from'vue';import{authReady}from'./auth';import{route,showBottomNav}from'./router';import BottomNav from'./components/BottomNav.vue';import HomePage from'./pages/HomePage.vue';import MessagesPage from'./pages/MessagesPage.vue';import MessageDetailPage from'./pages/MessageDetailPage.vue';import DataPage from'./pages/DataPage.vue';import LoginPage from'./pages/LoginPage.vue';const pages:any={orders:'订单',products:'商品',finance:'财务',settings:'设置'};const page=computed(()=>{if(route.value.path==='/login')return LoginPage;if(route.value.path==='/')return HomePage;if(route.value.path==='/messages')return MessagesPage;if(route.value.chatId)return MessageDetailPage;const k=route.value.path.split('/')[1];return{render:()=>h(DataPage,{kind:k,title:pages[k]||'页面'})}})</script>